sys_script_include.script:
var api_tasker_template = Class.create();
api_tasker_template.prototype = {
    initialize: function() {
		// TOD< when moving to next release add this
		//this.api_dtech = new api_dtech_common();
		this.api_tasker_ui_component_data = new api_tasker_ui_component_data();
		this.templateCopyMoveMethods = new template_Copy_Move_Methods();
    },

	activateTemplateTask: function(templateTaskId) {
		var activateResponse = {};
		activateResponse.taskActivated = false;
		// NOTE: state is read only.  Cannot use GlideRecordSecure here.
		//       GlideRecord is needed and the permissions are applied on tha Action
		var gr_template_task = new GlideRecord(api_dtech_common.CONST_DTECH_TEMPLATE_TASK_TABLE_NAME);
		if(gr_template_task.get(templateTaskId)){
			new Template_uiAction().uiAction_ActivateTemplateTask(gr_template_task);
			activateResponse.taskActivated = true;
		}
		return activateResponse;
	},

	changeTemplateTaskOrder: function(templateTaskId, newOrder){
		var changeOrder = {};
		changeOrder.taskActivated = false;
		// NOTE: state is read only.  Cannot use GlideRecordSecure here.
		//       GlideRecord is needed and the permissions are applied on tha Action
		var gr_template_task = new GlideRecord(api_dtech_common.CONST_DTECH_TEMPLATE_TASK_TABLE_NAME);
		if(gr_template_task.get(templateTaskId)){
			gr_template_task.route_order = newOrder;
			gr_template_task.update();
			changeOrder.taskActivated = true;
		}
		return changeOrder;		
	},

	cloneTemplate: function (template_id, new_template_name, new_template_owner){
		// this is JSON with new task and success flag
		var cloneResponse;
		cloneResponse =  this.templateCopyMoveMethods.cloneTemplate(template_id, new_template_name, new_template_owner);
		return cloneResponse;		
	}, 

	copyTemplateTask: function(templateTaskId, newParentId){
		var templateTaskCopied = false;
		templateTaskCopied =  this.templateCopyMoveMethods.copyTemplateTask(templateTaskId, newParentId);
		return templateTaskCopied;
	},

	copyTemplateTaskAndDescendants: function(templateTaskId, newParentId){
		var templateTaskCopied = false;
		templateTaskCopied =  this.templateCopyMoveMethods.copyTemplateTaskAndDescendants(templateTaskId, newParentId);
		return templateTaskCopied;
	},

	deactivateTemplateTask: function(templateTaskId) {
		var deactivateResponse = {};
		deactivateResponse.taskDeactivated = false;
		// NOTE: state is read only.  Cannot use GlideRecordSecure here.
		//       GlideRecord is needed and the permissions are applied on tha Action
		var gr_template_task = new GlideRecord(api_dtech_common.CONST_DTECH_TEMPLATE_TASK_TABLE_NAME);
		if(gr_template_task.get(templateTaskId)){
			new Template_uiAction().uiAction_DeactivateTemplateTask(gr_template_task);
			deactivateResponse.taskDeactivated = true;
		}
		return deactivateResponse;
	},

	getAssignmentInformation: function(templateTaskId){
		var lAssignmentInfo = {};
		var gr_template_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TEMPLATE_TASK_TABLE_NAME);
		if(gr_template_task.get(templateTaskId)){
			lAssignmentInfo = this.api_tasker_ui_component_data.getAssignmentInformationGR(gr_template_task);
		}
		return lAssignmentInfo;
	},

	getDurationInformation: function(templateTaskId){
		var lDurationInfo = {};
		var gr_template_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TEMPLATE_TASK_TABLE_NAME);
		if(gr_template_task.get(templateTaskId)){
			lDurationInfo = this.api_tasker_ui_component_data.getDurationInformationGR(gr_template_task);
		}
		return lDurationInfo;
	},

	getItemMembersInformation: function(templateTaskId){
		var lItemMembersInfo = {};
		var gr_template_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TEMPLATE_TASK_TABLE_NAME);
		if(gr_template_task.get(templateTaskId)){
			lItemMembersInfo = this.api_tasker_ui_component_data.getItemMembersInformationGR(gr_template_task);
		}
		return lItemMembersInfo;
	},

	getOperationalInformation: function(templateTaskId){
		var lOperationalInfo = {};
		var gr_template_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TEMPLATE_TASK_TABLE_NAME);
		if(gr_template_task.get(templateTaskId)){
			lOperationalInfo = this.api_tasker_ui_component_data.getOperationalInformationGR(gr_template_task);
		}
		return lOperationalInfo;
	},

	getUIActionParamaters: function(templateTaskId, action_name, action_sys_id){
		var params = {};
		var gr_template_task = new GlideRecordSecure(api_dtech_common.CONST_DTECH_TEMPLATE_TASK_TABLE_NAME);
		if(gr_template_task.get(templateTaskId)){
			params = this.getUIActionParamatersGR(gr_template_task, action_name, action_sys_id);
		}
		return params;
	},

	getUIActionParamatersGR: function(gr_template_task, action_name, action_sys_id){
		var params = {};
		var objTaskTemplateActions = this._get_ui_actions_icons();
		var arrItem = Object.keys(objTaskTemplateActions).filter(function(key){
			return objTaskTemplateActions[key].action_name==action_name || key==action_sys_id;});
		if(arrItem[0]){
			// get the key b/c the sys_id is the key of the array
			var ui_action_sys_id = arrItem[0];
			// load ui action parameters
			params = this._get_ui_actions_params(gr_template_task, ui_action_sys_id);
		}
		return params;
	},

	isTemplateNameUnique: function(template_name, template_level, template_ou, template_owner){
		var nameExists = false;
		var isTemplateNameUnique = false;
		nameExists = this.templateCopyMoveMethods.checkIfNameExists(template_name, template_level, template_ou, template_owner);
		isTemplateNameUnique = !nameExists;
		return isTemplateNameUnique;
	},

	moveTemplateTask: function(templateTaskId, newParentId){
		var templateTaskMoved = false;
		templateTaskMoved =  this.templateCopyMoveMethods.moveTemplateTask(templateTaskId, newParentId);
		return templateTaskMoved;
	},

	validateMetaData: function(methodCalled, metaData){
		var validMetaData = {};
		var isMetadataValid = false;
		if(typeof(metaData) == 'object'){
			if(metaData.objId && metaData.newParentId){
				validMetaData = metaData;
				isMetadataValid = true;
				validMetaData.success = true;
			}
		}
		validMetaData.validCallData = isMetadataValid;
		if(!isMetadataValid){
			gs.addErrorMessage("Tasker - " + methodCalled + " - invalid data: " + metaData);
			validMetaData.success = false;
			validMetaData.error = "invalid information provided for " + methodCalled;
		}
		return validMetaData;
	},

	validateNameCheckMetaData: function(methodCalled, metaData){
		var validMetaData = {};
		var isMetadataValid = false;
		if(typeof(metaData) == 'object'){
			if(metaData.new_template_name && metaData.new_template_name != '' &&
				metaData.template_level && metaData.template_level != '' &&
				metaData.template_ou && metaData.template_ou != '' &&
				metaData.template_owner && metaData.template_owner != ''){
				validMetaData = metaData;
				isMetadataValid = true;
			}
		}
		validMetaData.validCallData = isMetadataValid;
		if(!isMetadataValid){
			gs.addErrorMessage("Tasker - " + methodCalled + " - invalid data: " + metaData);
			validMetaData.success = false;
			validMetaData.error = "invalid information provided for " + methodCalled;
		}
		return validMetaData;	
	},

	validateCloneMetaData: function(methodCalled, metaData){
		var validMetaData = {};
		var isMetadataValid = false;
		if(typeof(metaData) == 'object'){
			if(metaData.template_id && metaData.template_id != '' &&
				metaData.new_template_owner && metaData.new_template_owner != '' &&
				metaData.new_template_name && metaData.new_template_name != ''){
				validMetaData = metaData;
				isMetadataValid = true;
			}
		}
		validMetaData.validCallData = isMetadataValid;
		if(!isMetadataValid){
			gs.addErrorMessage("Tasker - " + methodCalled + " - invalid data: " + metaData);
			validMetaData.success = false;
			validMetaData.error = "invalid information provided for " + methodCalled;
		}
		return validMetaData;	
	},

	// **************************************************************************************************
	// START - Context Menu Sectioin
	// **************************************************************************************************
	// NOTE: not sure if we want to burry this in code but, this would be how we would add the separators
	_get_ui_actions_context_menu_array: function(){
		var arrActions = [
			'298c61f5dbdcb780c18c59b2ca9619ab', // "name": "Activate" "action_name": "Activate Process Template Task"
			'06030bf6dbc8bf40c18c59b2ca961925',  // "name": "Deactivate" "action_name": "Deactivate Template Task"
			'separator', // add a separator
			'8381c90c1be10d107a948485604bcb2d' // "name": "Delete", "action_name" : "delete_template_task"
		];
		return arrActions;
	},

	_get_ui_actions_params: function(gr_task, action_sys_id){
		var params = {};
		// these parameters on passed to all
		params.task_sys_id = gr_task.getUniqueValue();
		var parent = gr_task.getDisplayValue("parent");
		params.is_top_template_task = (parent == '');
		var requestInfo = {};
		switch (action_sys_id){
			case '8381c90c1be10d107a948485604bcb2d': // "name": "Delete", "action_name" : "delete_template_task"
				params.action_name = "delete_template_task";
				params.template_sys_id = gr_task.getValue("tasker_process_definition");
				params.number_name = gr_task.getDisplayValue("number") + ': ' + gr_task.getValue('short_description');
				params.title = gs.getMessage('Delete') + ' ' + params.number_name + '?';
				break;
			case '298c61f5dbdcb780c18c59b2ca9619ab': // "name": "Activate" "action_name": "Activate Process Template Task"				
				params.action_name = "Activate Process Template Task";
				params.template_sys_id = gr_task.getValue("tasker_process_definition");

				params.number_name = gr_task.getDisplayValue("number") + ': ' + gr_task.getValue('short_description');
				params.title = gs.getMessage('Delete') + ' ' + params.number_name + '?';
				break;
			case '06030bf6dbc8bf40c18c59b2ca961925': // "name": "Deactivate" "action_name": "Deactivate Template Task"
				params.action_name = "Deactivate Template Task";
				params.template_sys_id = gr_task.getValue("tasker_process_definition");

				params.number_name = gr_task.getDisplayValue("number") + ': ' + gr_task.getValue('short_description');
				params.title = gs.getMessage('Delete') + ' ' + params.number_name + '?';
				break;
			default:			
				var errMsg = "Tasker - function: _get_ui_actions_params - an action was requested that isn't implemented.  UI Action sys_id: " + action_sys_id;
				gs.addErrorMessage(errMsg);
				break;
		}
		return params;

	},

	_get_ui_actions_icons: function(){
		// create an object with each action that has an icon
		// object key is uiAction sys_id, name comment added to make it easier to match sys_id to image
		// NOTE: this also contains the actoin name.  This allows us to use the array to find the sys_id for an action name
		var uiActionsIcons = {
			'8381c90c1be10d107a948485604bcb2d': { // "name": "Delete", (task), "action_name" : "delete_template_task"
				"action_name" : "delete_template_task",
				"image": "x_153465_discovert.DeleteTask16.svg"},
			'298c61f5dbdcb780c18c59b2ca9619ab': { // "name": "Activate" "action_name": "Activate Process Template Task"
				"action_name" : "Activate Process Template Task",
				"image": "x_153465_discovert.Activate16.svg"},
			'06030bf6dbc8bf40c18c59b2ca961925': { // "name": "Deactivate" "action_name": "Deactivate Template Task"
				"action_name" : "Deactivate Template Task",
				"image": "x_153465_discovert.Deactivate16.svg"}
		};
		return uiActionsIcons;
	},
	// **************************************************************************************************
	// END - Context Menu Sectioin
	// **************************************************************************************************

    type: 'api_tasker_template'
};
